Here's a complete implementation:

```csharp
// In Program.cs

// Configure request size limit (before builder.Build())
builder.Services.Configure<Microsoft.AspNetCore.Http.Features.FormOptions>(options =>
{
    options.MultipartBodyLengthLimit = 10 * 1024 * 1024; // 10MB
});

builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 10 * 1024 * 1024; // 10MB
});

// ... var app = builder.Build();

// Ensure uploads directory exists
Directory.CreateDirectory(Path.Combine(app.Environment.ContentRootPath, "uploads"));

app.MapPost("/upload", async (IFormFile file) =>
{
    // Validate content type
    string[] allowedTypes = ["image/jpeg", "image/png"];
    if (!allowedTypes.Contains(file.ContentType))
    {
        return Results.BadRequest("Only JPEG and PNG files are allowed.");
    }

    // Validate size
    if (file.Length > 10 * 1024 * 1024)
    {
        return Results.BadRequest("File size must not exceed 10MB.");
    }

    // Generate safe filename
    var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
    if (extension is not ".jpg" and not ".jpeg" and not ".png")
    {
        return Results.BadRequest("Invalid file extension.");
    }

    var fileName = $"{Guid.NewGuid()}{extension}";
    var uploadsPath = Path.Combine(app.Environment.ContentRootPath, "uploads");
    var filePath = Path.Combine(uploadsPath, fileName);

    await using var stream = new FileStream(filePath, FileMode.Create);
    await file.CopyToAsync(stream);

    return Results.Ok(new { fileName, size = file.Length });
})
.DisableAntiforgery(); // Required for API file uploads without form token
```

**Key points:**

- **`DisableAntiforgery()`** — since you have `UseAntiforgery()` globally, API endpoints accepting `IFormFile` need this unless you're sending the antiforgery token with the request.
- **Dual validation** — both content type and extension are checked to prevent spoofing.
- **GUID filenames** — avoids path traversal and name collisions.
- **Kestrel + FormOptions** — both limits must be set; Kestrel rejects the connection before `FormOptions` even applies if its limit is lower.

If you *do* want antiforgery enforced (e.g., uploads from your own HTML form), remove `.DisableAntiforgery()` and include the token in the multipart form.
